const history = items[0].json.watchHistory;
const genres = items[0].json.preferredGenres;

// Analyze patterns
const genreCounts = {};
history.forEach(item => {
  item.genre.forEach(g => {
    genreCounts[g] = (genreCounts[g] || 0) + 1;
  });
});

const topGenres = Object.entries(genreCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([g]) => g);

return [{ json: { topGenres, historyLength: history.length } }];
